type Tab='dashboard'|'incoming'|'checkin'|'stock'|'sales'|'receivables'|'finance'|'ceo_finance'|'supplies'|'buylab'|'leads'|'marketing'|'webhooks'|'jarvis';
type Row=Record<string,any>;

const money=(v:any)=>new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(Number(v||0));
const pct=(v:any)=>`${Number(v||0).toFixed(1)}%`;
const norm=(v:any)=>String(v||'').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
const num=(v:any)=>Number(v||0);
const sum=(values:number[])=>values.reduce((acc,value)=>acc+value,0);
const today=()=>new Date().toISOString().slice(0,10);
const addDays=(d:number)=>{const x=new Date();x.setDate(x.getDate()+d);return x.toISOString().slice(0,10)};
const feePct=(channel:string)=>norm(channel).includes('droper')?14:0;
const sizes=()=>Array.from({length:10},(_,i)=>String(36+i));
const cardPaymentMethods=new Set(['CXM','CXA']);
const paymentMethods=['PIX','CXM','CXA'];
const conditions=['9.5/10','9/10','8/10','7/10'];
const boxConditions=['caixa original','caixa replace'];
const nextCardDueDate=()=>{const x=new Date();x.setMonth(x.getMonth()+1,5);return x.toISOString().slice(0,10)};
const appendNote=(current:any,note:string)=>[String(current||'').trim(),'['+today()+'] '+note].filter(Boolean).join('\n');
type Period='month'|'30d'|'90d'|'year'|'all';
const periodOptions:{key:Period;label:string;short:string}[]=[
  {key:'month',label:'Mês atual',short:'Mês atual'},
  {key:'30d',label:'Últimos 30 dias',short:'30 dias'},
  {key:'90d',label:'Últimos 90 dias',short:'90 dias'},
  {key:'year',label:'Ano atual',short:'Ano atual'},
  {key:'all',label:'Histórico total',short:'Histórico'}
];
const parseDate=(value:any)=>{if(!value)return null; const raw=String(value); const d=new Date(raw.length===10?raw+'T12:00:00':raw); return Number.isNaN(d.getTime())?null:d};
const startOfToday=()=>{const d=new Date(); d.setHours(0,0,0,0); return d};
const periodStart=(period:Period)=>{const d=startOfToday(); if(period==='month')return new Date(d.getFullYear(),d.getMonth(),1); if(period==='30d'){d.setDate(d.getDate()-29);return d} if(period==='90d'){d.setDate(d.getDate()-89);return d} if(period==='year')return new Date(d.getFullYear(),0,1); return null};
const inPeriod=(value:any,period:Period)=>{if(period==='all')return true; const d=parseDate(value); const start=periodStart(period); if(!d||!start)return false; const end=startOfToday(); end.setHours(23,59,59,999); return d>=start&&d<=end};
const periodLabelFor=(period:Period)=>periodOptions.find(p=>p.key===period)?.label||'Histórico total';
const shortDateLabel=(d:Date)=>d.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'});
const monthLabel=(d:Date)=>d.toLocaleDateString('pt-BR',{month:'short'}).replace('.','');
const buildBuckets=(period:Period)=>{const now=startOfToday(); now.setHours(23,59,59,999); if(period==='all'||period==='year'){const end=new Date(now.getFullYear(),now.getMonth()+1,0,23,59,59,999); const buckets=[] as {label:string;start:Date;end:Date;entradas:number;saidas:number}[]; for(let i=5;i>=0;i--){const start=new Date(end.getFullYear(),end.getMonth()-i,1); const stop=new Date(end.getFullYear(),end.getMonth()-i+1,0,23,59,59,999); buckets.push({label:monthLabel(start),start,end:stop,entradas:0,saidas:0});} return buckets} const start=periodStart(period)||new Date(now.getFullYear(),now.getMonth(),1); const total=Math.max(1,now.getTime()-start.getTime()); const step=total/6; return Array.from({length:6},(_,i)=>{const bucketStart=new Date(start.getTime()+step*i); const bucketEnd=i===5?now:new Date(start.getTime()+step*(i+1)-1); return {label:shortDateLabel(bucketStart),start:bucketStart,end:bucketEnd,entradas:0,saidas:0}})};
const addToBucket=(buckets:{start:Date;end:Date;entradas:number;saidas:number}[],date:any,key:'entradas'|'saidas',amount:number)=>{const d=parseDate(date); if(!d)return; const bucket=buckets.find(b=>d>=b.start&&d<=b.end); if(bucket)bucket[key]+=amount};
const buildCashSeries=(receivables:Row[],accounts:Row[],incoming:Row[],period:Period)=>{const buckets=buildBuckets(period); receivables.forEach(r=>{const date=r.received_date||r.due_date||r.sale_date||r.created_at; if(inPeriod(date,period))addToBucket(buckets,date,'entradas',num(r.amount));}); accounts.forEach(a=>{const date=a.paid_date||a.due_date||a.created_at; if(inPeriod(date,period))addToBucket(buckets,date,'saidas',num(a.amount));}); incoming.forEach(i=>{const payment=String(i.payment_method||'PIX'); const date=i.purchase_date||i.created_at; if(!cardPaymentMethods.has(payment)&&inPeriod(date,period))addToBucket(buckets,date,'saidas',num(i.total_purchase_cost||i.cost_paid));}); return buckets.map(({label,entradas,saidas})=>({label,entradas,saidas}))};const navGroups:{title:string;items:{key:Tab;label:string;icon:string;badge?:string}[]}[]=[
  {title:'Fluxo',items:[{key:'dashboard',label:'Dashboard',icon:'◉'},{key:'incoming',label:'Nova compra',icon:'+'},{key:'sales',label:'Vendas',icon:'$'}]},
  {title:'Estoque',items:[{key:'checkin',label:'Check-in',icon:'✓'},{key:'stock',label:'Estoque físico',icon:'▤'}]},
  {title:'Financeiro',items:[{key:'receivables',label:'Recebimentos',icon:'◎'},{key:'finance',label:'Caixa & DRE',icon:'▦'},{key:'ceo_finance',label:'CEO / Finanças pessoais',icon:'◈'}]},
  {title:'Gestão',items:[{key:'supplies',label:'Insumos',icon:'⚙'},{key:'buylab',label:'BuyLab',icon:'BL'},{key:'leads',label:'Leads',icon:'LD'},{key:'webhooks',label:'Webhooks',icon:'↯'},{key:'jarvis',label:'Jarvis',icon:'✦',badge:'AI'}]},
  {title:'Marketing',items:[{key:'marketing',label:'Conteúdos',icon:'◇'}]}
];
const emptyIncoming={product_type:'tenis',brand:'',name:'',size:'42',sku:'',purchase_channel:'OLX',purchase_date:today(),cost_paid:'',payment_method:'PIX',listing_url:'',notes:''};
