const emptyMarketing={content_type:'Reels',funnel_area:'Aquisição',topic:'',product_focus:'',objective:'',reference_links:'',hook:'',script:'',caption:'',hashtags:'',status:'roteiro',planned_date:'',production_date:'',post_date:'',post_link:'',views_count:'',likes_count:'',comments_count:'',shares_count:'',saved_count:'',watched:false,result_note:''};
const emptyCeoFinance={month_ref:today().slice(0,7)+'-01',type:'gasto',category:'',description:'',amount:'',payment_method:'PIX',status:'pendente',due_date:'',paid_date:'',notes:''};
