  async function signUp(){if(!email||!password)return setToast('Informe e-mail e senha.'); const {error}=await supabase.auth.signUp({email,password}); if(error)return setToast(error.message); setToast('Usuário criado. Se o Supabase pedir confirmação, confirme no e-mail e depois clique em Entrar.');}
