  async function signOut(){await supabase.auth.signOut(); setSession(null);}

  async function createIncoming(){if(!incomingForm.name)return setToast('Informe o modelo / colorway.'); if(!incomingForm.cost_paid)return setToast('Informe o custo total pago.'); const cost=num(incomingForm.cost_paid), paymentMethod=String(incomingForm.payment_method||'PIX'); const payload={product_type:incomingForm.product_type,brand:incomingForm.brand,name:incomingForm.name,size:incomingForm.size,sku:incomingForm.sku,purchase_channel:incomingForm.purchase_channel,origin:incomingForm.purchase_channel,purchase_date:incomingForm.purchase_date||today(),cost_paid:cost,purchase_shipping:0,extra_cost:0,total_purchase_cost:cost,payment_method:paymentMethod,listing_url:incomingForm.listing_url,notes:incomingForm.notes,category:'',supplier_name:'',expected_arrival_date:null,invoice_due_date:null,expected_profit:0,roi_percent:0,created_by:session?.user?.id||null,status:'em_transito',checkin_status:'aguardando_checkin'}; const {data:createdIncoming,error}=await supabase.from('incoming_stock').insert(payload).select().single(); if(error)return setToast(error.message); if(cardPaymentMethods.has(paymentMethod)){const description=('Fatura '+paymentMethod+' - '+incomingForm.brand+' '+incomingForm.name+' '+incomingForm.size).replace(/\s+/g,' ').trim(); const {error:accountError}=await supabase.from('accounts_payable').insert({description,amount:cost,payment_method:paymentMethod,status:'pendente',category:'Cartão de crédito',due_date:nextCardDueDate(),source_type:'incoming_stock',source_id:createdIncoming?.id||null,notes:('Conta criada automaticamente a partir da compra '+incomingForm.brand+' '+incomingForm.name+' '+incomingForm.size+'.').replace(/\s+/g,' ').trim(),created_by:session?.user?.id||null}); if(accountError){setIncomingForm(emptyIncoming); setToast('Compra cadastrada, mas a conta do cartão não foi criada: '+accountError.message); await loadAll(); return;}} setIncomingForm(emptyIncoming); setToast('Compra cadastrada para chegada. Faça o check-in quando o produto estiver em mãos.'); await loadAll();}
  async function approveCheckin(item:Row){const draft=checkinForms[item.id]||{}; const checkedCondition=draft.condition||item.checked_condition||''; const checkedBox=draft.box_condition||item.checked_box_condition||''; const finalMin=num(draft.final_min_price??item.final_min_price); const finalTarget=num(draft.final_target_price??item.final_target_price); const finalIdeal=num(draft.final_ideal_price??item.final_ideal_price); const link=draft.listing_url??item.listing_url??''; const notes=draft.checkin_notes??item.checkin_notes??''; if(!checkedCondition)return setToast('Informe a condição final do produto.'); if(norm(item.product_type)==='tenis'&&!checkedBox)return setToast('Informe a condição da caixa.'); if(!finalMin&&!finalTarget&&!finalIdeal)return setToast('Informe pelo menos um preço final de venda.'); const cost=num(item.total_purchase_cost||item.cost_paid), salePrice=finalIdeal||finalTarget||finalMin, profit=salePrice-cost; const {error:stockError}=await supabase.from('stock_items').insert({incoming_stock_id:item.id,product_type:item.product_type,name:item.name,brand:item.brand,category:item.category||'',size:item.size,sku:item.sku,condition:checkedCondition,condition_rating:checkedCondition,box_condition:checkedBox,origin:item.origin||item.purchase_channel||'',supplier_name:item.supplier_name||'',listing_url:link,purchase_channel:item.purchase_channel,purchase_payment_method:item.payment_method,purchase_due_date:null,purchase_shipping:0,extra_cost:0,total_purchase_cost:cost,min_sale_price:finalMin,target_sale_price:finalTarget,ideal_sale_price:finalIdeal,entry_date:today(),checkin_date:today(),checkin_notes:notes,cost_base:cost,total_cost:cost,sale_price:salePrice,potential_profit:profit,status:'disponivel',health:'novo',notes:item.notes,created_by:session?.user?.id||null}); if(stockError)return setToast(stockError.message); const {error:updateError}=await supabase.from('incoming_stock').update({status:'recebido',checkin_status:'aprovado',checkin_date:today(),checked_condition:checkedCondition,checked_box_condition:checkedBox,final_min_price:finalMin,final_target_price:finalTarget,final_ideal_price:finalIdeal,listing_url:link,checkin_notes:notes}).eq('id',item.id); if(updateError)return setToast(updateError.message); setCheckinForms(p=>{const next={...p}; delete next[item.id]; return next}); if(checkinPanelId===item.id)setCheckinPanelId(''); setToast('Check-in aprovado e item enviado ao estoque físico.'); await loadAll();}
  async function cancelRelatedPurchaseAccount(item:Row,reason:string){const selectSource=await supabase.from('accounts_payable').select('id,notes').eq('source_type','incoming_stock').eq('source_id',item.id); let rows=selectSource.data||[]; if(!rows.length&&item.name){let q=supabase.from('accounts_payable').select('id,notes').neq('status','pago').ilike('description',`%${item.name}%`); if(item.payment_method)q=q.eq('payment_method',item.payment_method); const found=await q; rows=found.data||[];} if(rows.length){await Promise.all(rows.map((a:Row)=>supabase.from('accounts_payable').update({status:'cancelado',notes:appendNote(a.notes,reason)}).eq('id',a.id)));}}
