  async function registerSale(form=saleForm,itemArg?:Row,webhookId?:string){const item=itemArg||stock.find(s=>s.id===form.stock_item_id); if(!item)return setToast('Selecione um item do estoque.'); if(!form.gross_amount)return setToast('Informe o valor da venda.'); const channel=form.channel||'WhatsApp', gross=num(form.gross_amount), fee=gross*feePct(channel)/100, net=gross-fee, cost=num(item.total_cost||item.total_purchase_cost||item.cost_base), profit=net-cost, pay=norm(channel).includes('droper')?'a_receber':'recebido'; const {data,error}=await supabase.from('sales').insert({stock_item_id:item.id,sale_date:today(),channel,gross_amount:gross,shipping_amount:0,store_shipping_amount:0,discount_amount:0,marketplace_fee:fee,net_amount:net,cost_amount:cost,profit,payment_status:pay,sale_status:'vendido',customer_name:form.customer_name,customer_phone:form.customer_phone,expected_receipt_date:today(),payment_date:pay==='recebido'?today():null,droper_order_id:form.droper_order_id,tracking_code:form.tracking_code,webhook_event_id:webhookId||null,notes:form.notes,created_by:session?.user?.id||null}).select().single(); if(error)return setToast(error.message); await supabase.from('stock_items').update({status:'vendido',sale_channel:channel,sale_date:today(),closed_revenue:gross,marketplace_fee:fee,payment_status:pay,customer_name:form.customer_name,customer_phone:form.customer_phone,expected_receipt_date:today(),droper_order_id:form.droper_order_id,webhook_event_id:webhookId||null}).eq('id',item.id); await supabase.from('receivables').insert({sale_id:data.id,amount:net,due_date:today(),received_date:pay==='recebido'?today():null,status:pay,customer_name:form.customer_name,source_channel:channel,sale_date:today(),created_by:session?.user?.id||null}); const leadWarning=!webhookId?await createLeadFromSale(data,item,channel,form):''; if(webhookId) await supabase.from('webhook_events').update({processing_status:'venda_criada',processing_note:'Venda criada após confirmação manual. Lucro: '+money(profit)}).eq('id',webhookId); setSaleForm(emptySale); setWebhookConfirmId(''); setToast('Venda registrada. Líquido: '+money(net)+' | Lucro: '+money(profit)+'.'+(leadWarning?' Lead não foi criado: '+leadWarning:'')); await loadAll();}
  async function markRec(r:Row){await supabase.from('receivables').update({status:'recebido',received_date:today()}).eq('id',r.id); if(r.sale_id) await supabase.from('sales').update({payment_status:'recebido',payment_date:today()}).eq('id',r.sale_id); setToast('Recebimento baixado.'); await loadAll();}
  async function reverseSale(sale:Row,status:'cancelado'|'devolvido'){const label=status==='cancelado'?'cancelada':'devolvida'; const saleNote=status==='cancelado'?'Venda cancelada.':'Venda devolvida.'; const recNote=status==='cancelado'?'Recebimento cancelado por cancelamento de venda.':'Recebimento cancelado por devolu\u00e7\u00e3o de venda.'; const {error:saleError}=await supabase.from('sales').update({sale_status:status,payment_status:'cancelado',notes:appendNote(sale.notes,saleNote)}).eq('id',sale.id); if(saleError)return setToast(saleError.message); if(sale.stock_item_id){const {error:stockError}=await supabase.from('stock_items').update({status:'disponivel',sale_channel:null,sale_date:null,closed_revenue:0,marketplace_fee:0,payment_status:null,expected_receipt_date:null,customer_name:null,customer_phone:null,droper_order_id:null,webhook_event_id:null}).eq('id',sale.stock_item_id); if(stockError)return setToast(stockError.message);} const linked=receivables.filter(r=>r.sale_id===sale.id); if(linked.length){const updates=await Promise.all(linked.map(r=>supabase.from('receivables').update({status:'cancelado',received_date:null,notes:appendNote(r.notes,recNote)}).eq('id',r.id))); const recError=updates.find(r=>r.error)?.error; if(recError)return setToast(recError.message);}else{const {error:recError}=await supabase.from('receivables').update({status:'cancelado',received_date:null,notes:appendNote('',recNote)}).eq('sale_id',sale.id); if(recError)return setToast(recError.message);} setToast('Venda '+label+'. Item retornou ao estoque f\u00edsico.'); await loadAll();}
  async function cancelSale(sale:Row){await reverseSale(sale,'cancelado');}
  async function returnSale(sale:Row){await reverseSale(sale,'devolvido');}
