    function webhookWords(value:any){const stops=new Set(['tenis','produto','par','com','sem','para','masculino','feminino','original']); return norm(value).replace(/[^a-z0-9\s]/g,' ').split(/\s+/).filter(w=>w.length>=3&&!stops.has(w));}
  function webhookStrongNameMatch(detected:any,stockName:any){const words=webhookWords(detected); if(!words.length)return false; const name=norm(stockName); const hits=words.filter(w=>name.includes(w)).length; return hits>=Math.max(2,Math.ceil(words.length*.6));}
  function webhookMatches(w:Row){const sizeFiltered=availableStock.filter(s=>!w.detected_size||norm(s.size)===norm(w.detected_size)); let matches:Row[]=[]; if(w.detected_sku)matches=sizeFiltered.filter(s=>s.sku&&norm(s.sku)===norm(w.detected_sku)); if(!matches.length&&w.detected_product_name)matches=sizeFiltered.filter(s=>webhookStrongNameMatch(w.detected_product_name,s.name)); return matches;}
  function webhookCandidate(w:Row){const matches=webhookMatches(w); return matches.length===1?matches[0]:null;}
